const handleCheckout = async (datosEnvio) => {
    try {
        if (cart.length === 0) return;

        // Armamos la data para que coincida con el PedidoSchema del backend
        const pedidoData = {
            cliente: user?.id || user?._id,
            local: cart[0].local?._id || cart[0].local,
            items: cart.map(item => ({
                producto: item.producto, // String nombre
                precio: item.precioNuevo,
                cantidad: item.cantidad
            })),
            total: datosEnvio?.totalConEnvio || (total + 800),
            // IMPORTANTE: El backend pide puntoEntrega
            puntoEntrega: {
                direccion: "Dirección del Cliente", // Aquí podrías usar un prompt o estado de dirección
                lat: userCoords?.lat || 0,
                lng: userCoords?.lng || 0
            }
        };

        await api.crearPedido(pedidoData); 

        alert("¡Pedido confirmado! El stock ha sido actualizado en el local.");
        clearCart();
        navigate('/mis-pedidos');
    } catch (error) {
        console.error("Error al procesar pedido:", error);
        alert("Error al confirmar pedido. Revisa la consola.");
    }
};
